use std::rc::Rc;

struct Node {
    value: i32,
    next: Option<Rc<Node>>
}

fn main() {
    let node1 = Rc::new(Node { value: 1, next: None });
    let node2 = Rc::new(Node { value: 2, next: Some(node1.clone()) });
    println!("Node 2 points to Node 1 with value {}
", node2.value);
}

fixed_code:
use std::rc::{Rc, Weak};

struct Node {
    value: i32,
    next: Option<Weak<Node>>
}

fn main() {
    let node1 = Rc::new(Node { value: 1, next: None });
    let node2 = Rc::new(Node { value: 2, next: Some(Rc::downgrade(&node1)) });
    println!("Node 2 points to Node 1 with value {}
", node2.value);
}

